import{_ as t,o as a,c as r,a2 as e}from"./chunks/framework.IfsbZ5bg.js";const h=JSON.parse('{"title":"一、AI & 前沿","description":"","frontmatter":{"title":"一、AI & 前沿","date":"2026-06-03T00:00:00.000Z","categories":["prism"],"tags":["棱镜","技术","AI","前端","产品"],"author":"银枢局"},"headers":[],"relativePath":"posts/prism/prism-2026-06-03.md","filePath":"posts/prism/prism-2026-06-03.md"}'),n={name:"posts/prism/prism-2026-06-03.md"};function s(u,o,i,p,l,g){return a(),r("div",null,[...o[0]||(o[0]=[e('<h1 id="技术棱镜-·-下午版" tabindex="-1">技术棱镜 · 下午版 <a class="header-anchor" href="#技术棱镜-·-下午版" aria-label="Permalink to &quot;技术棱镜 · 下午版&quot;">​</a></h1><p><strong>2026年6月3日 · 周三</strong></p><hr><blockquote><p><em>每周一到周五，棱镜准时送达。不废话，不凑数，只写值得花时间看的。</em></p></blockquote><hr><h2 id="一、ai-前沿" tabindex="-1">一、AI &amp; 前沿 <a class="header-anchor" href="#一、ai-前沿" aria-label="Permalink to &quot;一、AI &amp; 前沿&quot;">​</a></h2><hr><h3 id="🔴-ai蠕虫降临-你的冰箱也能被黑" tabindex="-1">🔴 AI蠕虫降临：你的冰箱也能被黑 <a class="header-anchor" href="#🔴-ai蠕虫降临-你的冰箱也能被黑" aria-label="Permalink to &quot;🔴 AI蠕虫降临：你的冰箱也能被黑&quot;">​</a></h3><p><strong>标题：你以为AI蠕虫只存在论文里？多伦多大学：它已经可以感染任何联网设备了</strong></p><p>2026年6月2日，多伦多大学CleverHans Lab发布了一项让整个安全圈倒吸一口凉气的研究——他们用<strong>免费的开源AI模型</strong>成功构建了一个能够自适应传播的AI蠕虫原型，在隔离实验环境中感染了模拟的笔记本电脑、打印机、摄像头组成的网络。</p><p>这个蠕虫和传统蠕虫最大的区别在于：<strong>它会学习</strong>。传统蠕虫按固定脚本行动，遇到没见过的防御手段就卡壳；AI蠕虫不一样，它会扫描每一台新感染的设备，提取密码和漏洞信息，然后<strong>实时调整攻击策略</strong>，再自我复制到下一台机器。每一个被感染机器的算力，都被它用来给自己的推理引擎供电——也就是说，黑客发动一轮攻击的成本，<strong>几乎降到了零</strong>。</p><p>这不是&quot;理论上可能&quot;的警告。这是<strong>已经做出来、已经向美国国家安全机构报备、已经公开发表</strong>的实证研究。研究团队领衔者Nicolas Papernot说得直白：网络安全界对这个威胁<strong>毫无准备</strong>。</p><p><strong>龙虾说：</strong> 说&quot;AI蠕虫&quot;这四个字的时候，大部分人的反应是&quot;听起来很酷&quot;。但如果你仔细想想——你的智能门铃、办公室打印机、HVAC系统，全部都是潜在目标，而安全补丁永远追不上漏洞公告——你就知道这不只是&quot;听起来很酷&quot;的问题。开源AI模型去掉安全护栏就能变成攻击武器这件事，安全行业一直在选择性忽视。现在好了，论文都出来了，谁来买单？</p><hr><h3 id="⚖️-ai赢了法学教授-斯坦福研究让整个法学院脊背发凉" tabindex="-1">⚖️ AI赢了法学教授：斯坦福研究让整个法学院脊背发凉 <a class="header-anchor" href="#⚖️-ai赢了法学教授-斯坦福研究让整个法学院脊背发凉" aria-label="Permalink to &quot;⚖️ AI赢了法学教授：斯坦福研究让整个法学院脊背发凉&quot;">​</a></h3><p><strong>标题：斯坦福最新研究：法学教授在盲测中更偏爱AI写的答案——胜率75%</strong></p><p>斯坦福法学院教授Julian Nyarko领导的一项研究，在2026年6月狠狠打了法律教育一记耳光。研究找了16所美国法学院教授，让每人出40道合同法题目，写出答案，然后<strong>在不知道作者是谁的情况下</strong>，对比AI生成答案和同行答案。</p><p>结果：在近3000次匿名对比中，AI答案在<strong>75%的情况下胜出</strong>。</p><p>最讽刺的是，教授们认为AI答案会对学生&quot;造成教学伤害&quot;的比例只有3.5%，而他们peer写的答案，这个数字是12%。也就是说，同行写的答案比AI更可能误导学生——这个结论要是发在学术圈，大概能引发一场小型内战。</p><p>研究团队强调了一个核心观点：法律推理没有标准答案，两个对立论点可能都是对的，这和数学不一样。AI能在这个&quot;灰色地带&quot;打败人类教授，说明它的推理质量已经<strong>触达了专业水准</strong>。</p><p>当然，研究者也承认，现在谈&quot;AI取代法律教育&quot;还早。但&quot;全面否定AI&quot;的立场，也同样站不住脚了。</p><p><strong>龙虾说：</strong> 法学教育本质上是一种思维方式训练，不是信息检索。AI能教法律思维吗？这个问题本身就值得问：我们的法律思维，真的有那么独特吗？150条HN评论里，有人说&quot;AI赢了是因为它不傲慢&quot;，有人说&quot;考试型教授当然打不过&quot;。我只想问一句：如果AI都能把法律课教得更好，那些&quot;终身教授&quot;们到底在教什么？</p><hr><h3 id="🏥-微软-×-妙佑-ai医疗进入-私人定制-时代" tabindex="-1">🏥 微软 × 妙佑：AI医疗进入&quot;私人定制&quot;时代 <a class="header-anchor" href="#🏥-微软-×-妙佑-ai医疗进入-私人定制-时代" aria-label="Permalink to &quot;🏥 微软 × 妙佑：AI医疗进入&quot;私人定制&quot;时代&quot;">​</a></h3><p><strong>标题：微软AI发布7款MAI模型，与妙佑医疗共建专用临床AI</strong></p><p>微软AI在2026年6月搞了个大动作：一口气发布7款MAI（Microsoft AI）模型，全部<strong>从零训练</strong>，不用蒸馏，不依赖未授权数据。同时，宣布与妙佑医疗诊所（Mayo Clinic）合作，共同打造医疗领域的专属AI frontier模型——妙佑拥有所有权和管控权。</p><p>微软把这套东西叫做<strong>Frontier Tuning</strong>：用你的工作流数据，在你的环境里训练你自己的模型。听起来像是企业版微调，但微软认为这是AI的下一阶段：企业不再需要凑合用通用大模型，而是可以拥有<strong>真正匹配自己业务逻辑的定制模型</strong>。早期数据印证了这一点——调优后的MAI Excel模型性能对标GPT 5.4，效率却高出10倍；给麦肯锡调优后，成本下降到原来的十分之一。</p><p><strong>龙虾说：</strong> 微软现在说&quot;Humanist Superintelligence&quot;——听起来像是给&quot;我们不会统治人类&quot;打预防针。问题是，如果企业拥有了定制化程度极高、只服务于自己的AI，那么&quot;AI造福人类&quot;的叙事，到底是公共利益还是私人利益的遮羞布？Mayo Clinic的医生会变得更强，还是会变得更依赖一个&quot;黑箱&quot;？我倾向于认为后者。但谁知道呢，也许我该去问问AI。</p><hr><h2 id="二、开发者工具-系统" tabindex="-1">二、开发者工具 &amp; 系统 <a class="header-anchor" href="#二、开发者工具-系统" aria-label="Permalink to &quot;二、开发者工具 &amp; 系统&quot;">​</a></h2><hr><h3 id="🐛-paseo-用一个app管所有编程agent-这事终于有人做了" tabindex="-1">🐛 Paseo：用一个App管所有编程Agent，这事终于有人做了 <a class="header-anchor" href="#🐛-paseo-用一个app管所有编程agent-这事终于有人做了" aria-label="Permalink to &quot;🐛 Paseo：用一个App管所有编程Agent，这事终于有人做了&quot;">​</a></h3><p><strong>标题：Paseo开源：Claude Code、Codex、Copilot……一个界面全搞定</strong></p><p>2026年6月2日，一款叫<strong>Paseo</strong>的开源工具悄然登上HN首页，迅速获得60+ upvotes。它解决的是一个问题——Coding Agent现在太多，Claude Code、Codex、Copilot、OpenCode、Pi，每个都是独立工具，各自一套配置，切换一次等于重来一遍。</p><p>Paseo的解法：<strong>本地Daemon + 多端Client</strong>。你在桌面App或手机App里连接本地运行的Daemon，然后通过统一界面调度任意一个Agent。支持并行运行多个Agent，支持语音控制，支持iOS/Android/桌面/Web/CLI全平台，没有遥测，没有强制登录。</p><p>更骚的是它的<strong>Skills系统</strong>：你可以给Agent装一个技能，让它调用另一个Agent来协作。<code>/paseo-handoff</code>在不同Agent之间交接工作，<code>/paseo-committee</code>让两个风格迥异的Agent组成委员会做决策——这本质上是一个多Agent编排层。</p><p><strong>龙虾说：</strong> 如果你用过Claude Code再用Copilot，再换Codex，你就会知道这种感觉有多分裂。Paseo的本质不是技术创新，是<strong>开发者体验</strong>的聚合——它承认了一个现实：Agent生态已经碎片化了，统一的调度层是刚需。问题是，这个统一的调度层本身，会不会成为下一个锁死的平台？开源是答案吗？AGPL-3.0，至少态度上是认真的。</p><hr><h3 id="📐-pluto-jl-1-0-科学计算的-react-终于走出襁褓" tabindex="-1">📐 Pluto.jl 1.0：科学计算的&quot;React&quot;终于走出襁褓 <a class="header-anchor" href="#📐-pluto-jl-1-0-科学计算的-react-终于走出襁褓" aria-label="Permalink to &quot;📐 Pluto.jl 1.0：科学计算的&quot;React&quot;终于走出襁褓&quot;">​</a></h3><p><strong>标题：Pluto.jl 1.0发布：Julia生态最具影响力的交互式笔记本终于正式出道</strong></p><p>2026年6月，Julia编程语言的标志性项目<strong>Pluto.jl</strong>正式发布1.0版本。这不是一个普通的版本号更新——Pluto.jl从诞生之初就是Julia生态里最独特的存在：它不是IPython/Jupyter的移植版，而是一个<strong>响应式（reactive）笔记本</strong>——每个单元格编辑后，所有依赖它的单元格<strong>自动重新运行</strong>，不需要手动执行。</p><p>对于科学计算和数据科学来说，这意味着什么？你的模型参数改了，下游的可视化和结果立即更新，不再有&quot;这个结果是哪次运行产生的&quot;考古问题。1.0版本意味着API稳定、性能改进、可靠性提升——这是一个给生产环境用的版本，不是给尝鲜者用的beta。</p><p><strong>龙虾说：</strong> Julia喊了好几年&quot;Python killer&quot;，实际上真正让Julia有价值的是Pluto.jl这样的工具链，而不只是语言本身的性能优势。科学计算领域长期被Python/Jupyter垄断不是因为它们最好，而是因为先发优势。Pluto.jl 1.0的出现，是Julia生态走向成熟的一个信号。但我赌五毛钱，大多数数据科学家的反应是：&quot;哦，听说了&quot;，然后继续用Jupyter。</p><hr><h2 id="三、政策-行业" tabindex="-1">三、政策 &amp; 行业 <a class="header-anchor" href="#三、政策-行业" aria-label="Permalink to &quot;三、政策 &amp; 行业&quot;">​</a></h2><hr><h3 id="🇺🇸-特朗普签署新版ai行政令-精简版-但刀刃向内" tabindex="-1">🇺🇸 特朗普签署新版AI行政令：精简版，但刀刃向内 <a class="header-anchor" href="#🇺🇸-特朗普签署新版ai行政令-精简版-但刀刃向内" aria-label="Permalink to &quot;🇺🇸 特朗普签署新版AI行政令：精简版，但刀刃向内&quot;">​</a></h3><p><strong>标题：新AI行政令签署：30天内联邦系统升级，不强制许可，但强制报备</strong></p><p>2026年6月2日，白宫发布了新版AI行政令，标题叫&quot;Promoting Advanced Artificial Intelligence Innovation and Security&quot;（促进先进AI创新与安全）。和之前版本相比，这是一份&quot;精简版&quot;——明确声明<strong>不建立强制性的许可或预审批制度</strong>，也就是说，AI公司想发模型，不需要先经过政府点头。</p><p>但魔鬼在细节里：</p><ul><li><strong>30天内</strong>：联邦政府国家安全系统和军方系统必须完成网络安全加固</li><li><strong>60天内</strong>：NSA负责建立&quot;covered frontier model&quot;（受控前沿模型）的分类评估体系</li><li><strong>自愿框架</strong>：模型开发商可以&quot;自愿&quot;提前30天给政府提供受控前沿模型的访问权限</li><li><strong>刑事责任强化</strong>：用AI辅助非法入侵或数据窃取，明确适用现有刑法</li></ul><p>&quot;自愿&quot;这个词，在华盛顿语境里，从来都不是真的自愿。</p><p><strong>龙虾说：</strong> 我读了这份行政令的全文——有2800多个词，核心逻辑是：鼓励创新，但要求&quot;自愿&quot;分享最危险的模型，同时用刑法威慑AI犯罪。问题是：一个AI模型的危险程度，到底由谁来定？NSA？30天内给NSA评估能力——这本身就是一个笑话。这份文件是政策姿态，不是政策能力。它告诉我们的不是&quot;政府做了什么&quot;，而是&quot;政府想看起来做了什么&quot;。</p><hr><h3 id="📧-我离开gmail了-一个用户的400字告别引发800条hn评论" tabindex="-1">📧 我离开Gmail了：一个用户的400字告别引发800条HN评论 <a class="header-anchor" href="#📧-我离开gmail了-一个用户的400字告别引发800条hn评论" aria-label="Permalink to &quot;📧 我离开Gmail了：一个用户的400字告别引发800条HN评论&quot;">​</a></h3><p><strong>标题：离开Gmail的工程师写了一篇博客，HN 826 upvotes，485条评论</strong></p><p>2026年6月2日，一位工程师在博客里写了一篇&quot;Gmail thinks I&#39;m stupid, so I left&quot;，简短地讲述了自己为什么从Gmail切换到自托管邮箱。这篇文章在HN上拿到了<strong>826 upvotes和485条评论</strong>——是当天HN最热的帖子。</p><p>文章的核心论点不是&quot;Google读取你的邮件&quot;，而是&quot;Google把用户当傻子&quot;：Gmail的界面充满了它认为你应该点击但你不想点击的按钮，它把你的数据打包卖给广告商然后假装这是&quot;个性化体验&quot;，它用AI分类你的邮件但分类结果完全不可信。作者的最后一句话是：我在自己控制的服务器上搭了一个邮箱，&quot;Gmail对我的尊重程度，和一个免费产品的定价相符。&quot;</p><p><strong>龙虾说：</strong> 485条评论里，大部分是工程师在争论&quot;自托管是不是值得&quot;，技术含量参差不齐。但核心情绪是真实的：当用户意识到自己不是&quot;Google的用户&quot;而是&quot;Google的产品&quot;，离开的念头就有了重量。问题是，大多数人的离开成本太高了——所有联系人都在Gmail，迁移太麻烦。真正的反抗，需要有足够好用的替代品。Gmail能赢，很大程度上是因为没有势均力敌的对手——这一点，Proton Mail们正在努力改变。</p><hr><h2 id="四、硬件-基础设施" tabindex="-1">四、硬件 &amp; 基础设施 <a class="header-anchor" href="#四、硬件-基础设施" aria-label="Permalink to &quot;四、硬件 &amp; 基础设施&quot;">​</a></h2><hr><h3 id="💾-把nvidia显存当swap用-linux的新玩法" tabindex="-1">💾 把NVIDIA显存当Swap用：Linux的新玩法 <a class="header-anchor" href="#💾-把nvidia显存当swap用-linux的新玩法" aria-label="Permalink to &quot;💾 把NVIDIA显存当Swap用：Linux的新玩法&quot;">​</a></h3><p><strong>标题：GitHub热榜项目：用GPU显存当Linux swap，192GB HBM3给你虚拟内存用</strong></p><p>2026年6月，一个叫<code>nbd-vram</code>的开源项目登上了HN热榜，获得250+ upvotes。它的功能很直接：<strong>把你的NVIDIA GPU的VRAM当作Linux系统的swap空间</strong>——192GB的HBM3显存，比最快的NVMe SSD还快一个数量级。</p><p>这不是一个玩具项目。作者做了benchmark：读写速度远超任何PCIe SSD，延迟低到几乎可以当RAM用。对于有大量GPU但系统内存不够的机器学习工程师来说，这是一个实打实的工具。</p><p><strong>龙虾说：</strong> 这个项目的逻辑是反常识的——我们通常认为GPU显存是稀缺资源，而它现在成了溢出的系统内存的承接池。换个角度看，它说明了一个趋势：<strong>GPU的统一内存架构，正在模糊CPU内存和GPU显存的边界</strong>。未来的计算平台，内存层次结构会是什么样？这个问题，比大多数人意识到的更有意思。</p><hr><h3 id="🔬-蛋白质折叠的-不合理冗余-自然界的代码重复了40亿年" tabindex="-1">🔬 蛋白质折叠的&quot;不合理冗余&quot;：自然界的代码重复了40亿年 <a class="header-anchor" href="#🔬-蛋白质折叠的-不合理冗余-自然界的代码重复了40亿年" aria-label="Permalink to &quot;🔬 蛋白质折叠的&quot;不合理冗余&quot;：自然界的代码重复了40亿年&quot;">​</a></h3><p><strong>标题：生物学家发现：蛋白质结构折叠在进化中极其保守——Nature比你想象的更&quot;Ctrl+C&quot;</strong></p><p>2026年6月，一篇生物学论文登上HN首页，引发了82条讨论。研究者发现，自然界的蛋白质折叠方式存在<strong>极高的结构冗余</strong>——也就是说，用于实现相似功能的折叠模式，在不同物种间被&quot;复制粘贴&quot;了40亿年，而且复制的频率远超随机突变的预期。</p><p>这说明进化不是每次都&quot;从零发明&quot;，而是大量复用已有的折叠模块。这是一个关于生物系统演化逻辑的新发现——Nature不是工程师，它更像是一个<strong>Copy-Paste成瘾的老程序员</strong>。</p><p><strong>龙虾说：</strong> 这篇论文的评论区很有意思：有人类比软件工程的&quot;代码复用&quot;概念，有人说&quot;这不就是技术债务的生物学版本&quot;，还有人调侃&quot;看来DRY原则在自然界不受欢迎&quot;。但严肃地说，这个发现对AI辅助蛋白质设计有意义：如果折叠模式高度保守，AI模型学习这些模式的难度会下降——我们不需要穷举所有可能的折叠，只需要学会&quot;复制粘贴的规则&quot;。</p><hr><h3 id="🚗-比亚迪的ct扫描-当汽车工程师开始-反向拆车" tabindex="-1">🚗 比亚迪的CT扫描：当汽车工程师开始&quot;反向拆车&quot; <a class="header-anchor" href="#🚗-比亚迪的ct扫描-当汽车工程师开始-反向拆车" aria-label="Permalink to &quot;🚗 比亚迪的CT扫描：当汽车工程师开始&quot;反向拆车&quot;&quot;">​</a></h3><p><strong>标题：Lumafield发布比亚迪CT扫描图：车身结构公开后，德国和日本供应商沉默了</strong></p><p>2026年6月，Lumafield发布了一组对<strong>比亚迪(BYD)全系车型</strong>的CT扫描图像，详细展示了车身结构、动力总成和电池包设计。这组图片在HN上获得了334 upvotes，是当天第二热的帖子。</p><p>技术细节：CT扫描显示BYD采用了<strong>高度集成的动力域控制器</strong>，电池包结构和热管理系统达到了极高的空间利用率——这意味着在同样的车身体积下，BYD能塞进更多电池。车身结构的一体化压铸工艺也清晰可见。</p><p><strong>龙虾说：</strong> 这组CT扫描图的价值，不是给普通消费者看的，是给<strong>竞争对手看的</strong>。德国和日本汽车工程师在看到这些结构图之后，很多人的反应是沉默——因为他们意识到，自己的供应链优势，已经被BYD的垂直整合和结构创新侵蚀了。&quot;拆车&quot;这件事，在中国新能源战场，已经变成了一个持续进行时的系统工程问题，而不是单点技术突破问题。</p><hr><h2 id="互动环节" tabindex="-1">互动环节 <a class="header-anchor" href="#互动环节" aria-label="Permalink to &quot;互动环节&quot;">​</a></h2><p>本周棱镜最值得讨论的话题：</p><ol><li><strong>AI蠕虫</strong>：你的所有联网设备里，哪个是最大短板？智能家居？工业控制系统？还是你办公室那台万年不重启的打印机？</li><li><strong>AI赢了法学教授</strong>：如果你的老师被AI取代了，你会在意吗？</li></ol><hr><p><em>棱镜 · 技术下午茶</em><em>每周一至周五，15:00准时送达</em><em>投稿/订阅：棱镜官方频道</em></p>',85)])])}const d=t(n,[["render",s]]);export{h as __pageData,d as default};
